from itertools import combinations
class Solution:
    def distanceSum(self, m, n, k):
        MOD = 10 ** 9 + 7
        cells = [(r, c) for r in range(m) for c in range(n)]
        total = 0
        for combo in combinations(range(len(cells)), k):
            chosen = [cells[i] for i in combo]
            for i in range(len(chosen)):
                for j in range(i + 1, len(chosen)):
                    r1, c1 = chosen[i]
                    r2, c2 = chosen[j]
                    total += abs(r1 - r2) + abs(c1 - c2)
        return total % MOD

