class Solution:
    def distanceSum(self, m, n, k):
        MOD = 10 ** 9 + 7
        total_cells = m * n

        def pair_gap_sum(size):
            s = 0
            for d in range(1, size):
                s += d * (size - d)
            return s

        row_pair_sum = pair_gap_sum(m)
        col_pair_sum = pair_gap_sum(n)
        all_pairs_distance = (n * n * row_pair_sum + m * m * col_pair_sum) % MOD

        max_n = total_cells + 1
        fact = [1] * max_n
        for i in range(1, max_n):
            fact[i] = fact[i - 1] * i % MOD
        invfact = [1] * max_n
        invfact[max_n - 1] = pow(fact[max_n - 1], MOD - 2, MOD)
        for i in range(max_n - 2, -1, -1):
            invfact[i] = invfact[i + 1] * (i + 1) % MOD

        def comb(a, b):
            if b < 0 or b > a:
                return 0
            return fact[a] * invfact[b] % MOD * invfact[a - b] % MOD

        co_occurring = comb(total_cells - 2, k - 2)
        return co_occurring * all_pairs_distance % MOD

