var distanceSum = function(m, n, k) {
    const MOD = 1000000007n;
    const totalCells = m * n;

    function pairGapSum(size) {
        let s = 0n;
        for (let d = 1; d < size; d++) {
            s += BigInt(d) * BigInt(size - d);
        }
        return s;
    }

    const rowPairSum = pairGapSum(m);
    const colPairSum = pairGapSum(n);
    const allPairsDistance = (BigInt(n) * BigInt(n) % MOD * rowPairSum % MOD + BigInt(m) * BigInt(m) % MOD * colPairSum % MOD) % MOD;

    const maxN = totalCells + 1;
    const fact = new Array(maxN);
    fact[0] = 1n;
    for (let i = 1; i < maxN; i++) fact[i] = (fact[i - 1] * BigInt(i)) % MOD;
    function power(a, b, mod) {
        a %= mod;
        let r = 1n;
        while (b > 0n) {
            if (b & 1n) r = (r * a) % mod;
            a = (a * a) % mod;
            b >>= 1n;
        }
        return r;
    }
    const invfact = new Array(maxN);
    invfact[maxN - 1] = power(fact[maxN - 1], MOD - 2n, MOD);
    for (let i = maxN - 2; i >= 0; i--) invfact[i] = (invfact[i + 1] * BigInt(i + 1)) % MOD;
    function comb(a, b) {
        if (b < 0 || b > a) return 0n;
        return (fact[a] * invfact[b] % MOD) * invfact[a - b] % MOD;
    }

    const coOccurring = comb(totalCells - 2, k - 2);
    const ans = coOccurring * allPairsDistance % MOD;
    return Number(ans);
};
